WebLink.url:
{!REQUIRESCRIPT('/soap/ajax/29.0/connection.js')}
{!REQUIRESCRIPT('//ajax.googleapis.com/ajax/libs/jquery/1.10.2/jquery.min.js')}

if({!ISBLANK(Opportunity.OpportunityBundleId__c)})
{
	var opptyBundle = new sforce.SObject('OpportunityBundle__c');
	opptyBundle.OpportunityBundleName__c = 'Please fill in the name for this Opportunity Bundle';
	var result = sforce.connection.create([opptyBundle]);
	if(result[0].success == 'true')
	{
		 var o = new sforce.SObject("Opportunity");
		o.id = '{!Opportunity.Id}';
		// make the field change
		o.OpportunityBundle__c = result[0].id;

		// save the change
		sforce.connection.update([o]);
		window.location = '../' +result[0].id + '/e?retURL=/{!Opportunity.Id}';
	}
} else
{
	var error = document.getElementById('errorDiv_ep');
	if (error == null)
	{
		alert('Opportunity is already assigned to an Opportunity Bundle, remove the lookup to the Opportunity Bundle if you have to create a new Bundle.');
	} else
	{
		var removeLink = $("<a id='remove' href='#' style='color:#c00'>Cancel</a>").click(function(e) {
			var errorelem = document.getElementById('errorDiv_ep');
			errorelem.innerHTML = 'Error: Invalid Data. <br/>Review all error messages below to correct your data.';
			error.style.display='none';
		});
		error.innerHTML = 'Error: Opportunity is already assigned to an Opportunity Bundle, remove the lookup to the Opportunity Bundle if you have to create a new Bundle. ';
		error.style.display='block';
		$("#errorDiv_ep").append(removeLink);
	}
}
